import{_ as e,c as o,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Recursos da Plataforma: Modelos e Cotas | opencode-antigravity-auth","description":"Conheça os tipos de modelos e o sistema de cotas duplas do Antigravity Auth. Domine a seleção de modelos, configuração de Thinking e métodos de Google Search para otimizar o uso de cotas.","frontmatter":{"title":"Recursos da Plataforma: Modelos e Cotas | opencode-antigravity-auth","sidebarTitle":"Desbloquear o Sistema de Cotas Duplas","subtitle":"Recursos da Plataforma: Modelos e Cotas","description":"Conheça os tipos de modelos e o sistema de cotas duplas do Antigravity Auth. Domine a seleção de modelos, configuração de Thinking e métodos de Google Search para otimizar o uso de cotas.","order":2},"headers":[],"relativePath":"pt/NoeFabris/opencode-antigravity-auth/platforms/index.md","filePath":"pt/NoeFabris/opencode-antigravity-auth/platforms/index.md"}'),t={name:"pt/NoeFabris/opencode-antigravity-auth/platforms/index.md"};function d(r,a,l,n,u,c){return i(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="recursos-da-plataforma" tabindex="-1">Recursos da Plataforma <a class="header-anchor" href="#recursos-da-plataforma" aria-label="Permalink to &quot;Recursos da Plataforma&quot;">​</a></h1><p>Este capítulo ajuda você a entender em profundidade os modelos suportados, o sistema de cotas e os recursos da plataforma do plugin Antigravity Auth. Você aprenderá a escolher modelos adequados, configurar capacidades de Thinking, habilitar Google Search e maximizar a utilização de cotas.</p><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de começar</p><p>Antes de estudar este capítulo, certifique-se de que concluiu:</p><ul><li><a href="./../start/quick-install/">Instalação Rápida</a>: Instalação do plugin e autenticação inicial</li><li><a href="./../start/first-request/">Primeira Requisição</a>: Envio bem-sucedido da primeira requisição ao modelo</li></ul></div><h2 id="caminho-de-aprendizado" tabindex="-1">Caminho de Aprendizado <a class="header-anchor" href="#caminho-de-aprendizado" aria-label="Permalink to &quot;Caminho de Aprendizado&quot;">​</a></h2><p>Siga a ordem abaixo para dominar gradualmente os recursos da plataforma:</p><h3 id="_1-modelos-disponiveis" tabindex="-1">1. <a href="./available-models/">Modelos Disponíveis</a> <a class="header-anchor" href="#_1-modelos-disponiveis" aria-label="Permalink to &quot;1. [Modelos Disponíveis](./available-models/)&quot;">​</a></h3><p>Conheça todos os modelos disponíveis e suas configurações de variante</p><ul><li>Conheça Claude Opus 4.5, Sonnet 4.5 e Gemini 3 Pro/Flash</li><li>Entenda a distribuição de modelos nos dois pools de cotas: Antigravity e Gemini CLI</li><li>Domine o uso do parâmetro <code>--variant</code></li></ul><h3 id="_2-sistema-de-cotas-duplas" tabindex="-1">2. <a href="./dual-quota-system/">Sistema de Cotas Duplas</a> <a class="header-anchor" href="#_2-sistema-de-cotas-duplas" aria-label="Permalink to &quot;2. [Sistema de Cotas Duplas](./dual-quota-system/)&quot;">​</a></h3><p>Entenda como funciona o sistema de pools de cotas duplas: Antigravity e Gemini CLI</p><ul><li>Saiba como cada conta possui dois pools independentes de cotas Gemini</li><li>Habilite a configuração de fallback automático para duplicar as cotas</li><li>Especifique explicitamente qual pool de cotas o modelo deve usar</li></ul><h3 id="_3-google-search-grounding" tabindex="-1">3. <a href="./google-search-grounding/">Google Search Grounding</a> <a class="header-anchor" href="#_3-google-search-grounding" aria-label="Permalink to &quot;3. [Google Search Grounding](./google-search-grounding/)&quot;">​</a></h3><p>Habilite o Google Search para modelos Gemini, melhorando a precisão factual</p><ul><li>Permita que o Gemini busque informações da web em tempo real</li><li>Ajuste os limites de busca para controlar a frequência das pesquisas</li><li>Escolha a configuração adequada de acordo com as necessidades da tarefa</li></ul><h3 id="_4-modelos-thinking" tabindex="-1">4. <a href="./thinking-models/">Modelos Thinking</a> <a class="header-anchor" href="#_4-modelos-thinking" aria-label="Permalink to &quot;4. [Modelos Thinking](./thinking-models/)&quot;">​</a></h3><p>Domine a configuração e uso de modelos Thinking do Claude e Gemini 3</p><ul><li>Configure o thinking budget do Claude</li><li>Use o thinking level do Gemini 3 (minimal/low/medium/high)</li><li>Entenda o interleaved thinking e a estratégia de retenção de blocos de pensamento</li></ul><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após concluir este capítulo, você pode continuar aprendendo:</p><ul><li><a href="./../advanced/multi-account-setup/">Configuração de Múltiplas Contas</a>: Configure múltiplas contas Google para pool de cotas e balanceamento de carga</li><li><a href="./../advanced/account-selection-strategies/">Estratégias de Seleção de Contas</a>: Domine as melhores práticas das três estratégias: sticky, round-robin e hybrid</li><li><a href="./../advanced/configuration-guide/">Guia de Configuração</a>: Domine todas as opções de configuração para personalizar o comportamento do plugin conforme necessário</li></ul>',21)])])}const h=e(t,[["render",d]]);export{p as __pageData,h as default};
